+// =============================================================================
+// Q4_K Block Structure (GGML format)
+// =============================================================================
+
+/// Q4_K Block: 256 values quantized to 4 bits with k-means scales
+/// Memory layout: [f16 d][f16 dmin][12 bytes scales][128 bytes qs]
+/// Total: 144 bytes per 256 values = 0.5625 bytes/value
+/// This is ~1.8x smaller than Q8_0 (1.0625 bytes/value)
+struct block_q4_K {
+    half d;           // Super-block scale for quantized scales
+    half dmin;        // Super-block scale for quantized mins
+    uchar scales[12]; // Quantized scales and mins (3 bits each, k-means)
+    uchar qs[128];    // Quantized values (4 bits each, packed)
+};
+
+/// Decode scales and mins from packed 3-bit format
+/// Q4_K uses 8 sub-blocks of 32 values each
+/// scales[0-3] contain 6-bit values (high bits in scales[8-11])
+inline float4 decode_q4_k_scales(device const block_q4_K *b, int block_idx) {
+    // Each sub-block has a 6-bit scale and 6-bit min
+    // Packed in a complex interleaved format
+    const uchar *scales = b->scales;
+
+    float d = (float)b->d;
+    float dmin = (float)b->dmin;
+
+    // Decode scale and min for this block index (0-7)
+    float scale, min_val;
+
+    if (block_idx < 4) {
+        // First 4 blocks: low nibbles + bits from scales[8-11]
+        uchar sc_low = scales[block_idx] & 0x3F;
+        uchar mi_low = scales[block_idx + 4] & 0x3F;
+        scale = d * (float)sc_low;
+        min_val = dmin * (float)mi_low;
+    } else {
+        // Last 4 blocks: high nibbles + bits from scales[8-11]
+        int idx = block_idx - 4;
+        uchar sc_low = (scales[idx] >> 6) | ((scales[idx + 8] & 0xF) << 2);
+        uchar mi_low = (scales[idx + 4] >> 6) | ((scales[idx + 8] >> 4) << 2);
+        scale = d * (float)sc_low;
+        min_val = dmin * (float)mi_low;
+    }
+
+    return float4(scale, min_val, 0, 0);
+}
