+/// Down projection Q4_K (BATCHED): out[batch] = down_q4 @ activated[batch]
+kernel void moe_down_proj_q4_k(
+    device const uchar *down_q4 [[buffer(0)]],     // [n_embd, n_ff] Q4_K
+    device const float *activated [[buffer(1)]],   // [total_batch_size, n_ff]
+    device float *output [[buffer(2)]],            // [total_batch_size, n_embd]
+    constant uint &batch_size [[buffer(3)]],
+    constant uint &n_embd [[buffer(4)]],
+    constant uint &n_ff [[buffer(5)]],
+    constant uint &batch_offset [[buffer(6)]],
+    constant uint *token_indices [[buffer(7)]],
+    uint3 tgpig [[threadgroup_position_in_grid]],
+    uint tiisg [[thread_index_in_simdgroup]]
+) {
+    const int local_idx = tgpig.x;
+    const int row_idx = tgpig.y;
+
+    if (local_idx >= batch_size || row_idx >= n_embd) return;
+
+    const int actual_token_idx = (token_indices != nullptr) ? token_indices[local_idx] : (local_idx + batch_offset);
+    const int batch_idx = actual_token_idx;
+
+    // Calculate row stride for Q4_K (144 bytes per 256 elements)
+    const int blocks_per_row = (n_ff + 255) / 256;
+    const int nb00 = blocks_per_row * 144;
+    const int row_offset = row_idx * nb00;
+
+    device const block_q4_K *current_block = (device const block_q4_K *)(down_q4 + row_offset);
+
+    float sum = 0.0f;
+    const int num_blocks = n_ff / 256;
+    const int batch_activated_offset = batch_idx * n_ff;
+
+    for (int i = tiisg; i < num_blocks; i += 32) {
+        device const block_q4_K *b = current_block + i;
+        const float d = (float)b->d;
+        const float dmin = (float)b->dmin;
+        const int offset = batch_activated_offset + i * 256;
+
+        float block_sum = 0.0f;
+
+        for (int sb = 0; sb < 8; sb++) {
+            float scale, min_val;
+            if (sb < 4) {
+                scale = d * (float)(b->scales[sb] & 0x3F);
+                min_val = dmin * (float)(b->scales[sb + 4] & 0x3F);
+            } else {
+                int idx = sb - 4;
+                uchar sc = (b->scales[idx] >> 6) | ((b->scales[idx + 8] & 0xF) << 2);
+                uchar mi = (b->scales[idx + 4] >> 6) | ((b->scales[idx + 8] >> 4) << 2);
+                scale = d * (float)sc;
+                min_val = dmin * (float)mi;
+            }
+
+            const int qs_offset = sb * 16;
+            const int act_offset = offset + sb * 32;
+
+            for (int j = 0; j < 16; j++) {
+                uchar qbyte = b->qs[qs_offset + j];
+
+                float a0 = activated[act_offset + j * 2];
+                float a1 = activated[act_offset + j * 2 + 1];
+
+                block_sum += a0 * (scale * (float)(qbyte & 0xF) - min_val);
+                block_sum += a1 * (scale * (float)(qbyte >> 4) - min_val);
+            }
+        }
+
+        sum += block_sum;
+    }
+
+    sum = simd_sum(sum);
+
+    if (tiisg == 0) {
+        const int output_idx = batch_idx * n_embd + row_idx;
+        output[output_idx] = sum;
+    }
+}
