+            objc.encoderSetBuffer(encoder, gate_weights_q4, 0, 1);
+            objc.encoderSetBuffer(encoder, up_weights_q4, 0, 2);
+            objc.encoderSetBuffer(encoder, down_weights_q4, 0, 3);
+            objc.encoderSetBuffer(encoder, activated_buf, 0, 4);
+            objc.encoderSetBuffer(encoder, self.buf_intermediate, 0, 5);
+            objc.encoderSetBuffer(encoder, output, 0, 6);
+            objc.encoderSetBytes(encoder, @ptrCast(&batch_size_param), @sizeOf(u32), 7);
